import os
import zipfile
import tarfile

def create_archive(input_paths, output_archive_path, archive_format='zip'):
    if not isinstance(input_paths, list):
        input_paths = [input_paths]

    parent_dir = os.path.dirname(output_archive_path)
    if parent_dir and not os.path.exists(parent_dir):
        os.makedirs(parent_dir)

    if archive_format.lower() == 'zip':
        with zipfile.ZipFile(output_archive_path, 'w', zipfile.ZIP_DEFLATED) as zf:
            for path in input_paths:
                if not os.path.exists(path):
                    continue

                if os.path.isfile(path):
                    zf.write(path, arcname=os.path.basename(path))
                elif os.path.isdir(path):
                    root_dir_in_archive = os.path.basename(path)
                    for root, _, files in os.walk(path):
                        for file in files:
                            full_file_path = os.path.join(root, file)
                            rel_path = os.path.relpath(full_file_path, path)
                            arcname = os.path.join(root_dir_in_archive, rel_path)
                            zf.write(full_file_path, arcname=arcname)
    elif archive_format.lower() in ['tar', 'tar.gz', 'tgz', 'tar.bz2', 'tbz2', 'tar.xz', 'txz']:
        mode = 'w'
        if archive_format.lower() in ['tar.gz', 'tgz']:
            mode = 'w:gz'
        elif archive_format.lower() in ['tar.bz2', 'tbz2']:
            mode = 'w:bz2'
        elif archive_format.lower() in ['tar.xz', 'txz']:
            mode = 'w:xz'

        with tarfile.open(output_archive_path, mode) as tf:
            for path in input_paths:
                if not os.path.exists(path):
                    continue
                tf.add(path, arcname=os.path.basename(path))
    else:
        raise ValueError(f"Unsupported archive format: {archive_format}")
